const payload = $json || {};
const inputMessage = (payload['message '] || payload.message || payload.query || '').trim();
const fallback = (payload.prompt || payload.latest || '').trim();
const query = inputMessage || fallback;
if (!query) {
  throw new Error('No query provided to Web Search OpenAI workflow.');
}
return [{ json: { query, locale: payload.locale || 'en', original: payload } }];

const data = $json || {};
const results = Array.isArray(data.results) ? data.results : [];
if (!results.length) {
  return [{ json: { output: 'No web results were returned.', raw: data } }];
}

const lines = [];
results.slice(0, 5).forEach((r, idx) => {
  const title = r.title || r.url || 'Result';
  const url = r.url || r.href || '';
  const snippet = (r.content || r.snippet || '').replace(/\s+/g, ' ').trim();
  const price = r.price || '';
  const domain = url ? (new URL(url)).hostname.replace(/^www\./, '') : '';
  const parts = [`${idx + 1}. ${title}${domain ? ' (' + domain + ')' : ''}`];
  if (price) parts.push(`Price: ${price}`);
  if (snippet) parts.push(snippet);
  if (url) parts.push(url);
  lines.push(parts.join('
'));
});

const output = lines.join('

');
return [{ json: { output, results: results.slice(0, 5) } }];
